import sys
class Solution:
    def hasValidPath(self, grid):
        sys.setrecursionlimit(100000)
        m, n = len(grid), len(grid[0])
        if (m + n - 1) % 2 == 1:
            return False
        from functools import lru_cache
        @lru_cache(maxsize=None)
        def dfs(r, c, bal):
            bal += 1 if grid[r][c] == '(' else -1
            if bal < 0:
                return False
            if r == m - 1 and c == n - 1:
                return bal == 0
            ok = False
            if r + 1 < m:
                ok = ok or dfs(r + 1, c, bal)
            if c + 1 < n:
                ok = ok or dfs(r, c + 1, bal)
            return ok
        return dfs(0, 0, 0)

