class Solution:
    def hasValidPath(self, grid):
        m, n = len(grid), len(grid[0])
        if grid[0][0] == ')' or grid[m - 1][n - 1] == '(' or (m + n) % 2 == 0:
            return False
        states = [[set() for _ in range(n)] for _ in range(m)]
        states[0][0].add(1)
        for r in range(m):
            for c in range(n):
                if r == 0 and c == 0:
                    continue
                delta = 1 if grid[r][c] == '(' else -1
                cur = set()
                if r > 0:
                    cur |= states[r - 1][c]
                if c > 0:
                    cur |= states[r][c - 1]
                for b in cur:
                    nb = b + delta
                    if nb >= 0:
                        states[r][c].add(nb)
        return 0 in states[m - 1][n - 1]

