var hasValidPath = function(grid) {
    const m = grid.length, n = grid[0].length;
    if (grid[0][0] === ')' || grid[m - 1][n - 1] === '(' || (m + n) % 2 === 0) return false;
    const states = Array.from({ length: m }, () => Array.from({ length: n }, () => new Set()));
    states[0][0].add(1);
    for (let r = 0; r < m; r++) {
        for (let c = 0; c < n; c++) {
            if (r === 0 && c === 0) continue;
            const delta = grid[r][c] === '(' ? 1 : -1;
            const cur = new Set();
            if (r > 0) for (const b of states[r - 1][c]) cur.add(b);
            if (c > 0) for (const b of states[r][c - 1]) cur.add(b);
            for (const b of cur) {
                const nb = b + delta;
                if (nb >= 0) states[r][c].add(nb);
            }
        }
    }
    return states[m - 1][n - 1].has(0);
};
